from flask import Flask, request, jsonify, session
from werkzeug.security import check_password_hash, generate_password_hash
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import secrets
import time
import sqlite3
import os

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(16))
app.config['SESSION_COOKIE_SECURE'] = True
app.config['SESSION_COOKIE_HTTPONLY'] = True
app.config['SESSION_COOKIE_SAMESITE'] = 'Lax'

# Rate limiting
limiter = Limiter(
    app,
    key_func=get_remote_address,
    default_limits=["100 per hour"]
)

# Database setup
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, username TEXT UNIQUE, password_hash TEXT, mfa_enabled BOOLEAN, mfa_secret TEXT)''')
    conn.commit()
    conn.close()

# Mock MFA implementation
def generate_totp(secret):
    # In production, use a proper TOTP library like pyotp
    return str(secrets.randbelow(1000000)).zfill(6)

def verify_totp(secret, token):
    # In production, use a proper TOTP library like pyotp
    return token == generate_totp(secret)

# Authentication functions
def authenticate_user(username, password):
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT id, username, password_hash, mfa_enabled, mfa_secret FROM users WHERE username = ?", (username,))
    user = c.fetchone()
    conn.close()
    
    if user and check_password_hash(user[2], password):
        return {
            'id': user[0],
            'username': user[1],
            'mfa_enabled': user[3],
            'mfa_secret': user[4]
        }
    return None

# Routes
@app.route('/login', methods=['POST'])
@limiter.limit("5 per minute")
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    user = authenticate_user(username, password)
    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    session['user_id'] = user['id']
    session['username'] = user['username']
    
    if user['mfa_enabled']:
        # Generate and store OTP
        otp = generate_totp(user['mfa_secret'])
        session['otp'] = otp
        session['otp_timestamp'] = time.time()
        return jsonify({'mfa_required': True, 'message': 'MFA required'})
    
    # No MFA, grant access
    return jsonify({'message': 'Login successful', 'access_token': secrets.token_urlsafe(32)})

@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    data = request.get_json()
    token = data.get('token')
    
    if not token:
        return jsonify({'error': 'Token required'}), 400
    
    if 'otp' not in session:
        return jsonify({'error': 'No active MFA session'}), 400
    
    # Check if OTP is still valid (5 minutes)
    if time.time() - session.get('otp_timestamp', 0) > 300:
        session.pop('otp', None)
        return jsonify({'error': 'OTP expired'}), 400
    
    # Verify OTP
    if token == session['otp']:
        session.pop('otp', None)
        session.pop('otp_timestamp', None)
        return jsonify({'message': 'MFA verified', 'access_token': secrets.token_urlsafe(32)})
    
    return jsonify({'error': 'Invalid OTP'}), 401

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    # This endpoint bypasses MFA checks
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    user = authenticate_user(username, password)
    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    # Direct login bypasses MFA
    return jsonify({
        'message': 'Direct login successful',
        'access_token': secrets.token_urlsafe(32),
        'user_id': user['id']
    })

@app.route('/logout', methods=['POST'])
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})

# Initialize database
init_db()

